'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneGhostProps {
    className?: string;
    onFileSelect?: (file: File | null) => void;
    defaultImage?: string;
    maxSize?: number;
}

export function AvatarDropzoneGhost({
    className,
    onFileSelect,
    defaultImage,
    maxSize = 5 * 1024 * 1024,
}: AvatarDropzoneGhostProps) {
    return (
        <SingleImageDrop
            variant="ghost"
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            showRemoveButton={true}
            className={className}
        />
    );
}
